/**
 * Generate KIT_MANIFEST.md — a machine-readable contract for the @/components/ui kit,
 * for agentic coding. For every exported `*Props` type it lists each prop with its
 * required/optional status, type, and JSDoc summary, so an agent knows EXACTLY what it
 * must pass (e.g. the now-required `data-testid`, accessible-name props) without reading
 * source. Auto-generated from the TYPES (TS compiler API) so it cannot drift.
 *
 * Run: node scripts/gen-kit-manifest.mjs   (CI/check should run with --check to fail on drift)
 */
import { createRequire } from 'node:module'
import { fileURLToPath } from 'node:url'
import path from 'node:path'
import fs from 'node:fs'

const require = createRequire(import.meta.url)
const ts = require('typescript')

const ROOT = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..')
const BARREL = path.join(ROOT, 'src/components/ui/index.ts')
const OUT = path.join(ROOT, 'src/components/ui/KIT_MANIFEST.md')

const tsconfigPath = ts.findConfigFile(ROOT, ts.sys.fileExists, 'tsconfig.json')
const { config } = ts.readConfigFile(tsconfigPath, ts.sys.readFile)
const parsed = ts.parseJsonConfigFileContent(config, ts.sys, path.dirname(tsconfigPath))
const program = ts.createProgram({ rootNames: [BARREL, ...parsed.fileNames], options: parsed.options })
const checker = program.getTypeChecker()

const barrelSource = program.getSourceFile(BARREL)
if (!barrelSource) throw new Error(`barrel not found: ${BARREL}`)
const barrelSymbol = checker.getSymbolAtLocation(barrelSource)
const exports = checker.getExportsOfModule(barrelSymbol)

const summary = (sym) => {
  const d = ts.displayPartsToString(sym.getDocumentationComment(checker)).replace(/\s+/g, ' ').trim()
  return d.length > 140 ? d.slice(0, 137) + '…' : d
}
const clean = (t) => t.replace(/\s+/g, ' ').replace(/import\([^)]+\)\./g, '').trim()

// Resolve a *Props type alias symbol → list of {name, required, type, doc}, or null if not introspectable.
function propsOf(sym) {
  const type = checker.getDeclaredTypeOfSymbol(sym)
  if (!type) return null
  const isUnion = !!(type.flags & ts.TypeFlags.Union)
  const props = checker.getPropertiesOfType(type)
  if (!props.length) return null
  const decl = sym.declarations?.[0] ?? barrelSource
  const rows = props
    // Keep only KIT-AUTHORED props (declared in our repo). Drops the ~290 inherited
    // HTML/aria attributes from React.ComponentProps so the contract shows only what
    // the kit actually defines (incl. the intersected required `data-testid`/`aria-label`).
    .filter((p) => {
      const decls = p.getDeclarations() || []
      return decls.length === 0 || decls.some((d) => !d.getSourceFile().fileName.includes('node_modules'))
    })
    .filter((p) => !p.getName().startsWith('__'))
    .map((p) => {
      const optional = !!(p.flags & ts.SymbolFlags.Optional)
      let tStr = ''
      try { tStr = clean(checker.typeToString(checker.getTypeOfSymbolAtLocation(p, decl))) } catch { tStr = '?' }
      if (tStr.length > 90) tStr = tStr.slice(0, 87) + '…'
      return { name: p.getName(), required: !optional, type: tStr, doc: summary(p) }
    })
    // Required first, then alphabetical — agents scan the required block.
    .sort((a, b) => (a.required === b.required ? a.name.localeCompare(b.name) : a.required ? -1 : 1))
  return { isUnion, rows }
}

const components = []
for (const ex of exports) {
  const name = ex.getName()
  if (!/Props$/.test(name)) continue
  const aliased = ex.flags & ts.SymbolFlags.Alias ? checker.getAliasedSymbol(ex) : ex
  const info = propsOf(aliased)
  if (!info) continue
  const compName = name.replace(/Props$/, '')
  components.push({ compName, typeName: name, ...info })
}
components.sort((a, b) => a.compName.localeCompare(b.compName))

let md = `<!-- AUTO-GENERATED by scripts/gen-kit-manifest.mjs — DO NOT EDIT. Run the script to refresh. -->
# Kit component contract (\`@/components/ui\`)

Import every UI component from \`@/components/ui\` (never antd, never raw DOM, never deep paths).
This is the machine-readable contract: each component's **required** props are listed first.
Cross-cutting rules every agent must follow:

- **\`data-testid\` is REQUIRED** on all functional/container/value/action components (Button, Card,
  Input, Select, Table, Form, …). It must be **globally unique** (a build-time Vite plugin fails the
  build on cross-file duplicates). Use a module-scoped kebab id, e.g. \`user-form-email\`.
- **Accessible name is REQUIRED** where there's no visible label: icon-only \`Button\` needs \`tooltip\`
  (or \`aria-label\`); \`FormField\` needs \`label\` or \`aria-label\`; closable \`Tag\`/\`Alert\` need \`closeLabel\`.
- Collection items (List/Table rows, Menu/Tabs items, Select options) auto-derive their testid from
  the container's testid — give the CONTAINER a testid and the rows are covered.
- Never import \`antd\`, never use raw \`<button>/<input>/<select>/<textarea>\` (Biome blocks both).

${components.length} components documented.

`

for (const c of components) {
  md += `## ${c.compName}${c.isUnion ? ' _(discriminated union — see source for variant-specific props)_' : ''}\n\n`
  const req = c.rows.filter((r) => r.required)
  const opt = c.rows.filter((r) => !r.required)
  if (req.length) {
    md += `**Required:**\n\n| prop | type | notes |\n|---|---|---|\n`
    for (const r of req) md += `| \`${r.name}\` | \`${r.type}\` | ${r.doc} |\n`
    md += `\n`
  } else {
    md += `_No always-required props._\n\n`
  }
  if (opt.length) {
    md += `<details><summary>Optional props (${opt.length})</summary>\n\n| prop | type | notes |\n|---|---|---|\n`
    for (const r of opt) md += `| \`${r.name}\` | \`${r.type}\` | ${r.doc} |\n`
    md += `\n</details>\n\n`
  }
}

const check = process.argv.includes('--check')
if (check) {
  const existing = fs.existsSync(OUT) ? fs.readFileSync(OUT, 'utf-8') : ''
  if (existing.trim() !== md.trim()) {
    console.error('KIT_MANIFEST.md is stale — run `node scripts/gen-kit-manifest.mjs` and commit.')
    process.exit(1)
  }
  console.log('KIT_MANIFEST.md up to date.')
} else {
  fs.writeFileSync(OUT, md)
  console.log(`Wrote ${OUT} (${components.length} components).`)
}
